#include <iostream>
#include <string>
using namespace std;

class Student {
private:
    string name;
    int rollNo;

public:
    // Default Constructor
    Student() {
        name = "Unknown";
        rollNo = 0;
        cout << "Default Constructor called" << endl;
    }

    // Parameterized Constructor
    Student(string n, int r) {
        name = n;
        rollNo = r;
        cout << "Parameterized Constructor called for " << name << endl;
    }

    // Destructor
    ~Student() {
        cout << "Destructor called for " << name << endl;
    }

    void display() {
        cout << "Name: " << name << ", Roll No: " << rollNo << endl;
    }
};

int main() {
    Student s1;                    // Calls default constructor
    Student s2("Amit", 101);       // Calls parameterized constructor

    s1.display();
    s2.display();

    return 0;
}

#include <iostream>
#include <cstring>
using namespace std;

class String {
private:
    char* str;
    int length;

public:
    // Parameterized Constructor
    String(const char* s) {
        length = strlen(s);
        str = new char[length + 1];
        strcpy(str, s);
        cout << "Parameterized Constructor: " << str << endl;
    }

    // Copy Constructor (Shallow Copy)
    String(const String& obj) {
        length = obj.length;
        str = obj.str;  // Copies address, not the actual data
        cout << "Copy Constructor called" << endl;
    }

    // Destructor
    ~String() {
        cout << "Destructor called for: " << str << endl;
        delete[] str;
    }

    void display() {
        cout << "String: " << str << ", Length: " << length << endl;
    }
};

int main() {
    String s1("Hello World");
    String s2 = s1;  // Calls copy constructor

    s1.display();
    s2.display();

    return 0;
}

#include <iostream>
using namespace std;

class ArrayManager {
private:
    int* arr;
    int size;

public:
    // Parameterized Constructor - dynamic allocation
    ArrayManager(int n) {
        size = n;
        arr = new int[size];

        // Initialize array with indices
        for(int i = 0; i < size; i++) {
            arr[i] = i * 10;
        }
        cout << "Constructor: Allocated array of size " << size << endl;
    }

    // Destructor - cleanup dynamic memory
    ~ArrayManager() {
        delete[] arr;
        cout << "Destructor: Freed allocated memory" << endl;
    }

    void display() {
        cout << "Array elements: ";
        for(int i = 0; i < size; i++) {
            cout << arr[i] << " ";
        }
        cout << endl;
    }

    // Function to demonstrate this pointer
    ArrayManager* getAddress() {
        return this;
    }
};

int main() {
    // Object created on stack
    ArrayManager obj1(5);
    obj1.display();
    cout << "Address of obj1: " << obj1.getAddress() << endl;

    // Object created on heap using new
    ArrayManager* obj2 = new ArrayManager(3);
    obj2->display();
    cout << "Address of obj2: " << obj2->getAddress() << endl;

    // Must manually delete heap object
    delete obj2;

    cout << "Stack object going out of scope..." << endl;
    return 0;
}
